  1	import * as React from 'react';
  2	import {
  3	  Checkbox,
  4	  TextInput,
  5	  TextInputTypes,
  6	  Toolbar,
  7	  ToolbarGroup,
  8	  ToolbarItem,
  9	  ToolbarContent,
 10	  ToolbarFilter,
 11	  Select,
 12	  SelectList,
 13	  SelectOption,
 14	  MenuToggleElement,
 15	  MenuToggle,
 16	  TextInputGroup,
 17	  TextInputGroupMain,
 18	  ToolbarChipGroup,
 19	  ToolbarChip
 20	} from '@patternfly/react-core';
 21	import {
 22	  ActiveFilter,
 23	  ActiveFiltersInfo,
 24	  DEFAULT_LABEL_OPERATION,
 25	  FILTER_ACTION_UPDATE,
 26	  FilterType,
 27	  AllFilterTypes,
 28	  LabelOperation,
 29	  ToggleType,
 30	  ActiveTogglesInfo
 31	} from '../../types/Filters';
 32	import * as FilterHelper from '../FilterList/FilterHelper';
 33	import { PromisesRegistry } from '../../utils/CancelablePromises';
 34	import { kialiStyle } from 'styles/StyleUtils';
 35	import { LabelFilters } from './LabelFilter';
 36	import { arrayEquals } from 'utils/Common';
 37	import { labelFilter } from './CommonFilters';
 38	import { HistoryManager, location } from 'app/History';
 39	import { serverConfig } from 'config';
 40	import { PFColors } from '../Pf/PfColors';
 41	import { t } from 'utils/I18nUtils';
 42	import { connect } from 'react-redux';
 43	import { KialiAppState } from 'store/Store';
 44	import { languageSelector } from 'store/Selectors';
 45	import { classes } from 'typestyle';
 46	
 47	const toolbarStyle = kialiStyle({
 48	  padding: 0,
 49	  rowGap: 'var(--pf-t--global--spacer--300)',
 50	  $nest: {
 51	    '& > .pf-v6-c-toolbar__content': {
 52	      paddingLeft: 0
 53	    }
 54	  }
 55	});
 56	
 57	const bottomPadding = kialiStyle({
 58	  paddingBottom: 'var(--pf-t--global--spacer--300)'
 59	});
 60	
 61	const formSelectStyle = kialiStyle({
 62	  borderColor: PFColors.BorderColorLight100,
 63	  backgroundColor: PFColors.BackgroundColor200,
 64	  minWidth: '170px',
 65	  maxWidth: '170px'
 66	});
 67	
 68	const filterSelectStyle = kialiStyle({
 69	  maxHeight: '350px',
 70	  overflow: 'auto'
 71	});
 72	
 73	type ReduxProps = {
 74	  language: string;
 75	};
 76	
 77	type StatefulFiltersProps = ReduxProps & {
 78	  children?: React.ReactNode;
 79	  childrenFirst?: boolean;
 80	  cleanState?: boolean; // For shared components, state is not saved in the URL
 81	  initialFilters: FilterType[];
 82	  initialToggles?: ToggleType[];
 83	  onFilterChange: (active: ActiveFiltersInfo) => void;
 84	  onToggleChange?: (active: ActiveTogglesInfo) => void;
 85	  ref?: React.RefObject<StatefulFiltersComponent>;
 86	  toolbarClass?: string;
 87	};
 88	
 89	interface StatefulFiltersState {
 90	  activeFilters: ActiveFiltersInfo;
 91	  activeToggles: number;
 92	  currentFilterType: FilterType;
 93	  currentValue: string;
 94	  filterTypes: FilterType[];
 95	  focusedItemIndex: number | null;
 96	  isFilterTypeOpen: boolean;
 97	  isFilterValueOpen: boolean;
 98	}
 99	
100	export class FilterSelected {
101	  static selectedFilters: ActiveFilter[] | undefined = undefined;
102	  static opSelected: LabelOperation;
103	
104	  static init = (filterTypes: FilterType[]): ActiveFiltersInfo => {
105	    let active = FilterSelected.getSelected();
106	
107	    if (!FilterSelected.isInitialized()) {
108	      active = FilterHelper.getFiltersFromURL(filterTypes);
109	      FilterSelected.setSelected(active);
110	    } else if (!FilterHelper.filtersMatchURL(filterTypes, active)) {
111	      active = FilterHelper.setFiltersToURL(filterTypes, active);
112	      FilterSelected.setSelected(active);
113	    }
114	
115	    return active;
116	  };
117	
118	  static resetFilters = (): void => {
119	    FilterSelected.selectedFilters = undefined;
120	  };
121	
122	  static setSelected = (activeFilters: ActiveFiltersInfo): void => {
123	    FilterSelected.selectedFilters = activeFilters.filters;
124	    FilterSelected.opSelected = activeFilters.op;
125	  };
126	
127	  static getSelected = (): ActiveFiltersInfo => {
128	    return { filters: FilterSelected.selectedFilters ?? [], op: FilterSelected.opSelected ?? 'or' };
129	  };
130	
131	  static isInitialized = (): boolean => {
132	    return FilterSelected.selectedFilters !== undefined;
133	  };
134	}
135	
136	// Column toggles
137	export class Toggles {
138	  static checked: ActiveTogglesInfo = new Map<string, boolean>();
139	  static numChecked = 0;
140	
141	  static init = (toggles: ToggleType[]): number => {
142	    Toggles.checked.clear();
143	    Toggles.numChecked = 0;
144	
145	    // Prefer URL settings
146	    const urlParams = new URLSearchParams(location.getSearch());
147	
148	    toggles.forEach(t => {
149	      const urlIsChecked = HistoryManager.getBooleanParam(`${t.name}Toggle`, urlParams);
150	      const isChecked = urlIsChecked === undefined ? t.isChecked : urlIsChecked;
151	      Toggles.checked.set(t.name, isChecked);
152	
153	      if (isChecked) {
154	        Toggles.numChecked++;
155	      }
156	    });
157	    return Toggles.numChecked;
158	  };
159	
160	  static setToggle = (name: string, value: boolean): number => {
161	    HistoryManager.setParam(`${name}Toggle`, `${value}`);
162	    Toggles.checked.set(name, value);
163	    Toggles.numChecked = value ? Toggles.numChecked++ : Toggles.numChecked--;
164	
165	    return Toggles.numChecked;
166	  };
167	
168	  static getToggles = (): ActiveTogglesInfo => {
169	    return new Map<string, boolean>(Toggles.checked);
170	  };
171	}
172	
173	const dividerStyle = kialiStyle({
174	  borderRight: `1px solid ${PFColors.ColorLight300}`,
175	  padding: '0.5rem',
176	  display: 'inherit'
177	});
178	
179	const paddingStyle = kialiStyle({
180	  padding: '0 0.5rem 0.5rem 0.5rem',
181	  width: '100%'
182	});
183	
184	export type StatefulFiltersRef = React.RefObject<StatefulFiltersComponent>;
185	
186	export class StatefulFiltersComponent extends React.Component<StatefulFiltersProps, StatefulFiltersState> {
187	  private textInputRef: React.RefObject<HTMLDivElement>;
188	  private promises = new PromisesRegistry();
189	
190	  constructor(props: StatefulFiltersProps) {
191	    super(props);
192	    this.textInputRef = React.createRef<HTMLInputElement>();
193	    this.state = {
194	      activeFilters: this.props.cleanState ? { filters: [], op: 'or' } : FilterSelected.init(this.props.initialFilters),
195	      activeToggles: Toggles.init(this.props.initialToggles ?? []),
196	      currentFilterType: this.props.initialFilters[0],
197	      filterTypes: this.props.initialFilters,
198	      isFilterTypeOpen: false,
199	      isFilterValueOpen: false,
200	      currentValue: '',
201	      focusedItemIndex: null
202	    };
203	  }
204	
205	  componentDidMount(): void {
206	    this.loadDynamicFilters();
207	  }
208	
209	  private loadDynamicFilters = (): void => {
210	    // Call all loaders from FilterTypes and set results in state
211	    const filterTypePromises = this.props.initialFilters.map(async ft => {
212	      if (ft.loader) {
213	        return ft.loader().then(values => {
214	          ft.filterValues = values;
215	
216	          return {
217	            category: ft.category,
218	            placeholder: ft.placeholder,
219	            filterType: ft.filterType,
220	            action: ft.action,
221	            filterValues: ft.filterValues
222	          };
223	        });
224	      } else {
225	        return Promise.resolve(ft);
226	      }
227	    });
228	
229	    this.promises
230	      .registerAll('filterType', filterTypePromises)
231	      .then(types => this.setState({ filterTypes: types }))
232	      .catch(err => {
233	        if (!err.isCanceled) {
234	          console.debug(err);
235	        }
236	      });
237	  };
238	
239	  private getCurrentFilterTypes = (): FilterType => {
240	    return (
241	      this.props.initialFilters.find(f => f.category === this.state.currentFilterType.category) ??
242	      this.props.initialFilters[0]
243	    );
244	  };
245	
246	  componentDidUpdate(prevProps: StatefulFiltersProps, prevState: StatefulFiltersState): void {
247	    // If the props filters changed (e.g. different values), some state update is necessary
248	    if (
249	      this.props.initialFilters !== prevProps.initialFilters &&
250	      !arrayEquals(this.props.initialFilters, prevProps.initialFilters, (t1, t2) => {
251	        return (
252	          t1.category === t2.category &&
253	          arrayEquals(t1.filterValues, t2.filterValues, (v1, v2) => {
254	            return v1.id === v2.id && v1.title === v2.title;
255	          })
256	        );
257	      })
258	    ) {
259	      const current = this.getCurrentFilterTypes();
260	      const active = FilterHelper.setFiltersToURL(this.props.initialFilters, this.state.activeFilters);
261	
262	      this.setState({
263	        currentFilterType: current,
264	        filterTypes: this.props.initialFilters,
265	        activeFilters: active
266	      });
267	
268	      this.loadDynamicFilters();
269	    } else if (
270	      !this.props.cleanState &&
271	      !FilterHelper.filtersMatchURL(this.state.filterTypes, this.state.activeFilters)
272	    ) {
273	      FilterHelper.setFiltersToURL(this.state.filterTypes, this.state.activeFilters);
274	    }
275	
276	    // If the input text changes in typeahead, filter the select options according to the input text value
277	    if (
278	      this.state.currentFilterType.filterType === AllFilterTypes.typeAhead &&
279	      this.state.currentValue !== prevState.currentValue
280	    ) {
281	      const current = Object.assign({}, this.getCurrentFilterTypes());
282	
283	      current.filterValues = current.filterValues.filter(menuItem =>
284	        String(menuItem.title).toLowerCase().includes(this.state.currentValue.toLowerCase())
285	      );
286	
287	      this.setState({
288	        currentFilterType: current,
289	        isFilterValueOpen: true
290	      });
291	    }
292	  }
293	
294	  componentWillUnmount(): void {
295	    this.promises.cancelAll();
296	  }
297	
298	  updateActiveFilters = (activeFilters: ActiveFiltersInfo): void => {
299	    const cleanFilters = FilterHelper.setFiltersToURL(this.state.filterTypes, activeFilters);
300	    FilterSelected.setSelected(cleanFilters);
301	    this.setState({ activeFilters: cleanFilters, currentValue: '' });
302	    this.props.onFilterChange(cleanFilters);
303	  };
304	
305	  filterAdded = (field: FilterType, value: string): void => {
306	    const activeFilters = this.state.activeFilters;
307	    const activeFilter: ActiveFilter = {
308	      category: field.category,
309	      value: value
310	    };
311	
312	    // For filters that need to be updated in place instead of added, we check if it is already defined in activeFilters
313	    const current = activeFilters.filters.filter(filter => filter.category === field.category);
314	    if (field.action === FILTER_ACTION_UPDATE && current.length > 0) {
315	      current.forEach(filter => (filter.value = value));
316	    } else {
317	      activeFilters.filters.push(activeFilter);
318	    }
319	
320	    this.updateActiveFilters(activeFilters);
321	  };
322	
323	  selectFilterType = (value: string): void => {
324	    const { currentFilterType } = this.state;
325	    const filterType = this.state.filterTypes.filter(filter => filter.category === value)[0];
326	
327	    if (currentFilterType !== filterType) {
328	      this.setState({
329	        currentValue: '',
330	        currentFilterType: filterType
331	      });
332	    }
333	
334	    this.setState({ isFilterTypeOpen: false });
335	  };
336	
337	  filterValueSelected = (valueId?: string | number): void => {
338	    const { currentFilterType } = this.state;
339	    const filterValue = currentFilterType.filterValues.find(filter => filter.id === valueId);
340	
341	    if (filterValue && !this.isActive(currentFilterType, filterValue.title)) {
342	      this.filterAdded(currentFilterType, filterValue.title);
343	    }
344	
345	    setTimeout(() => this.setState({ isFilterValueOpen: false }));
346	  };
347	
348	  updateCurrentValue = (value: string): void => {
349	    this.setState({ currentValue: value, focusedItemIndex: null });
350	  };
351	
352	  onValueKeyDown = (keyEvent: React.KeyboardEvent): void => {
353	    const { currentValue, currentFilterType } = this.state;
354	
355	    if (keyEvent.key === 'Enter') {
356	      if (currentValue && currentValue.length > 0 && !this.isActive(currentFilterType, currentValue)) {
357	        this.filterAdded(currentFilterType, currentValue);
358	      }
359	
360	      this.setState({ currentValue: '' });
361	      keyEvent.stopPropagation();
362	      keyEvent.preventDefault();
363	    }
364	  };
365	
366	  onTypeaheadInputKeyDown = (keyEvent: React.KeyboardEvent): void => {
367	    const { isFilterValueOpen, focusedItemIndex, currentFilterType } = this.state;
368	
369	    if (keyEvent.key === 'ArrowUp' || keyEvent.key === 'ArrowDown') {
370	      let indexToFocus: number | null = null;
371	
372	      if (this.state.isFilterValueOpen) {
373	        if (keyEvent.key === 'ArrowUp') {
374	          // When no index is set or at the first index, focus to the last, otherwise decrement focus index
375	          if (focusedItemIndex === null || focusedItemIndex === 0) {
376	            indexToFocus = currentFilterType.filterValues.length - 1;
377	          } else {
378	            indexToFocus = focusedItemIndex - 1;
379	          }
380	        } else if (keyEvent.key === 'ArrowDown') {
381	          // When no index is set or at the last index, focus to the first, otherwise increment focus index
382	          if (focusedItemIndex === null || focusedItemIndex === currentFilterType.filterValues.length - 1) {
383	            indexToFocus = 0;
384	          } else {
385	            indexToFocus = focusedItemIndex + 1;
386	          }
387	        }
388	
389	        this.setState({ focusedItemIndex: indexToFocus });
390	      }
391	    } else if (keyEvent.key === 'Enter') {
392	      const focusedItem = focusedItemIndex !== null ? currentFilterType.filterValues[focusedItemIndex] : null;
393	
394	      if (isFilterValueOpen && focusedItem) {
395	        this.filterValueSelected(focusedItem.id);
396	        this.setState({ currentValue: '', focusedItemIndex: null });
397	      }
398	    }
399	  };
400	
401	  isActive = (type: FilterType, value: string): boolean => {
402	    return this.state.activeFilters.filters.some(active => value === active.value && type.category === active.category);
403	  };
404	
405	  removeFilter = (category: string | ToolbarChipGroup, value: string | ToolbarChip): void => {
406	    const filterCategory = typeof category === 'string' ? category : category.key;
407	    const filterValue = typeof value === 'string' ? value : value.key;
408	
409	    const updated = this.state.activeFilters.filters.filter(
410	      x => x.category !== filterCategory || x.value !== filterValue
411	    );
412	
413	    if (updated.length !== this.state.activeFilters.filters.length) {
414	      this.updateActiveFilters({ filters: updated, op: this.state.activeFilters.op });
415	    }
416	  };
417	
418	  clearFilters = (): void => {
419	    this.updateActiveFilters({ filters: [], op: DEFAULT_LABEL_OPERATION });
420	  };
421	
422	  onFilterTypeToggle = (): void => {
423	    this.setState({
424	      isFilterTypeOpen: !this.state.isFilterTypeOpen
425	    });
426	  };
427	
428	  onFilterValueToggle = (): void => {
429	    this.setState({
430	      isFilterValueOpen: !this.state.isFilterValueOpen
431	    });
432	
433	    this.textInputRef?.current?.focus();
434	  };
435	
436	  onCheckboxChange = (checked: boolean, event: React.FormEvent<HTMLInputElement>): void => {
437	    this.setState({ activeToggles: Toggles.setToggle(event.currentTarget.name, checked) });
438	    if (this.props.onToggleChange) {
439	      this.props.onToggleChange(Toggles.getToggles());
440	    }
441	  };
442	
443	  renderInput = (): React.ReactNode => {
444	    const { currentFilterType, currentValue } = this.state;
445	
446	    if (!currentFilterType) {
447	      return null;
448	    }
449	
450	    if (currentFilterType.filterType === AllFilterTypes.typeAhead) {
451	      const typeaheadToggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
452	        <MenuToggle
453	          id="filter_select_value-toggle"
454	          ref={toggleRef}
455	          variant="typeahead"
456	          onClick={this.onFilterValueToggle}
457	          isExpanded={this.state.isFilterValueOpen}
458	          isFullWidth
459	        >
460	          <TextInputGroup isPlain>
461	            <TextInputGroupMain
462	              value={this.state.currentValue}
463	              onClick={this.onFilterValueToggle}
464	              onChange={(_event, value) => this.updateCurrentValue(value)}
465	              id="typeahead-select-input"
466	              autoComplete="off"
467	              innerRef={this.textInputRef}
468	              onKeyDown={this.onTypeaheadInputKeyDown}
469	              placeholder={t(this.state.currentFilterType.placeholder)}
470	              role="combobox"
471	              isExpanded={this.state.isFilterValueOpen}
472	              aria-controls="select-typeahead-listbox"
473	            />
474	          </TextInputGroup>
475	        </MenuToggle>
476	      );
477	
478	      return (
479	        <Select
480	          id="filter_select_value"
481	          selected={this.state.activeFilters.filters.map(filter => filter.value)}
482	          onSelect={(_event, value) => this.filterValueSelected(value)}
483	          onOpenChange={isFilterValueOpen => this.setState({ isFilterValueOpen })}
484	          toggle={typeaheadToggle}
485	          isOpen={this.state.isFilterValueOpen}
486	          aria-label="Filter Select Value"
487	          className={filterSelectStyle}
488	          shouldFocusFirstItemOnOpen={false}
489	        >
490	          <SelectList isAriaMultiselectable data-test="istio-type-dropdown">
491	            {currentFilterType.filterValues.length > 0 ? (
492	              currentFilterType.filterValues.map((filter, index) => (
493	                <SelectOption
494	                  id={filter.id}
495	                  key={filter.id}
496	                  value={filter.id}
497	                  isFocused={this.state.focusedItemIndex === index}
498	                  label={t(filter.title)}
499	                >
500	                  {t(filter.title)}
501	                </SelectOption>
502	              ))
503	            ) : (
504	              <SelectOption id="filter_no_results" key="filter_no_results" value="no_results" isDisabled={true}>
505	                {t('No results found')}
506	              </SelectOption>
507	            )}
508	          </SelectList>
509	        </Select>
510	      );
511	    } else if (currentFilterType.filterType === AllFilterTypes.select) {
512	      const selectToggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
513	        <MenuToggle
514	          id="filter_select_value-toggle"
515	          ref={toggleRef}
516	          onClick={this.onFilterValueToggle}
517	          isExpanded={this.state.isFilterValueOpen}
518	          isFullWidth
519	        >
520	          {t(this.state.currentFilterType.placeholder)}
521	        </MenuToggle>
522	      );
523	
524	      return (
525	        <Select
526	          id="filter_select_value"
527	          selected={FilterSelected.getSelected().filters.map(filter => filter.value)}
528	          onSelect={(_event, value) => {
529	            this.filterValueSelected(value);
530	            this.updateCurrentValue(value as string);
531	          }}
532	          onOpenChange={isFilterValueOpen => this.setState({ isFilterValueOpen })}
533	          toggle={selectToggle}
534	          isOpen={this.state.isFilterValueOpen}
535	          aria-label="Filter Select Value"
536	          className={filterSelectStyle}
537	        >
538	          <SelectList>
539	            {currentFilterType.filterValues.map(filter => (
540	              <SelectOption id={filter.id} key={filter.id} value={filter.id}>
541	                {t(filter.title)}
542	              </SelectOption>
543	            ))}
544	          </SelectList>
545	        </Select>
546	      );
547	    } else if (
548	      currentFilterType.filterType === AllFilterTypes.label ||
549	      currentFilterType.filterType === AllFilterTypes.nsLabel
550	    ) {
551	      return (
552	        <LabelFilters
553	          value={currentValue}
554	          onChange={this.updateCurrentValue}
555	          filterAdd={value => this.filterAdded(currentFilterType, value)}
556	          isActive={value => this.isActive(currentFilterType, value)}
557	        />
558	      );
559	    } else {
560	      return (
561	        <TextInput
562	          id="filter_input_value"
563	          type={currentFilterType.filterType as TextInputTypes}
564	          value={currentValue}
565	          aria-label="Filter Input Value"
566	          placeholder={t(currentFilterType.placeholder)}
567	          onChange={(_event, value) => this.updateCurrentValue(value)}
568	          onKeyDown={e => this.onValueKeyDown(e)}
569	          style={{ width: 'auto' }}
570	        />
571	      );
572	    }
573	  };
574	
575	  renderChildren = (): React.ReactNode => {
576	    return (
577	      this.props.children && (
578	        <ToolbarGroup style={{ marginRight: '10px' }}>
579	          {Array.isArray(this.props.children) ? (
580	            (this.props.children as Array<any>).map(
581	              (child, index) =>
582	                child && (
583	                  <ToolbarItem
584	                    key={`toolbar_statefulFilters_${index}`}
585	                    className={index === (this.props.children as Array<any>).length - 1 ? paddingStyle : dividerStyle}
586	                  >
587	                    {child}
588	                  </ToolbarItem>
589	                )
590	            )
591	          ) : (
592	            <ToolbarItem>{this.props.children}</ToolbarItem>
593	          )}
594	        </ToolbarGroup>
595	      )
596	    );
597	  };
598	
599	  render(): React.ReactNode {
600	    const showIncludeToggles = serverConfig.kialiFeatureFlags.uiDefaults.list.showIncludeToggles;
601	
602	    const { currentFilterType, activeFilters } = this.state;
603	
604	    const hasActiveFilters =
605	      this.state.activeFilters.filters.some(f => f.category === labelFilter.category) ||
606	      this.state.currentFilterType.filterType === AllFilterTypes.label;
607	
608	    const filterTypeToggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
609	      <MenuToggle
610	        id="filter_select_type-toggle"
611	        className={formSelectStyle}
612	        ref={toggleRef}
613	        onClick={this.onFilterTypeToggle}
614	        isExpanded={this.state.isFilterTypeOpen}
615	        isFullWidth
616	      >
617	        {t(currentFilterType.category)}
618	      </MenuToggle>
619	    );
620	
621	    const filterValueToggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
622	      <MenuToggle
623	        id="filter_select_value-toggle"
624	        ref={toggleRef}
625	        onClick={this.onFilterValueToggle}
626	        isExpanded={this.state.isFilterValueOpen}
627	        isFullWidth
628	      >
629	        {t(activeFilters.op)}
630	      </MenuToggle>
631	    );
632	
633	    return (
634	      <>
635	        <Toolbar
636	          id="filter-selection"
637	          className={this.props.toolbarClass ? classes(toolbarStyle, this.props.toolbarClass) : toolbarStyle}
638	          clearAllFilters={this.clearFilters}
639	        >
640	          {this.props.childrenFirst && this.renderChildren()}
641	          <ToolbarContent>
642	            <ToolbarGroup variant="filter-group">
643	              {this.state.filterTypes.map((ft, i) => (
644	                <ToolbarFilter
645	                  key={`toolbar_filter-${ft.category}`}
646	                  chips={activeFilters.filters
647	                    .filter(af => af.category === ft.category)
648	                    .map(af => ({
649	                      key: af.value,
650	                      node: t(af.value)
651	                    }))}
652	                  deleteChip={this.removeFilter}
653	                  categoryName={{ key: ft.category, name: t(ft.category) }}
654	                >
655	                  {i === 0 && (
656	                    <Select
