186	export class StatefulFiltersComponent extends React.Component<StatefulFiltersProps, StatefulFiltersState> {
187	  private textInputRef: React.RefObject<HTMLDivElement>;
188	  private promises = new PromisesRegistry();
189	
190	  constructor(props: StatefulFiltersProps) {
191	    super(props);
192	    this.textInputRef = React.createRef<HTMLInputElement>();
193	    this.state = {
194	      activeFilters: this.props.cleanState ? { filters: [], op: 'or' } : FilterSelected.init(this.props.initialFilters),
195	      activeToggles: Toggles.init(this.props.initialToggles ?? []),
