208	
209	  private loadDynamicFilters = (): void => {
210	    // Call all loaders from FilterTypes and set results in state
211	    const filterTypePromises = this.props.initialFilters.map(async ft => {
212	      if (ft.loader) {
213	        return ft.loader().then(values => {
214	          ft.filterValues = values;
215	
216	          return {
217	            category: ft.category,
218	            placeholder: ft.placeholder,
219	            filterType: ft.filterType,
220	            action: ft.action,
221	            filterValues: ft.filterValues
222	          };
223	        });
224	      } else {
225	        return Promise.resolve(ft);
226	      }
227	    });
228	
229	    this.promises
230	      .registerAll('filterType', filterTypePromises)
231	      .then(types => this.setState({ filterTypes: types }))
232	      .catch(err => {
233	        if (!err.isCanceled) {
234	          console.debug(err);
235	        }
236	      });
237	  };
238	
239	  private getCurrentFilterTypes = (): FilterType => {
240	    return (
241	      this.props.initialFilters.find(f => f.category === this.state.currentFilterType.category) ??
242	      this.props.initialFilters[0]
243	    );
244	  };
245	
246	  componentDidUpdate(prevProps: StatefulFiltersProps, prevState: StatefulFiltersState): void {
247	    // If the props filters changed (e.g. different values), some state update is necessary
248	    if (
249	      this.props.initialFilters !== prevProps.initialFilters &&
250	      !arrayEquals(this.props.initialFilters, prevProps.initialFilters, (t1, t2) => {
251	        return (
252	          t1.category === t2.category &&
253	          arrayEquals(t1.filterValues, t2.filterValues, (v1, v2) => {
254	            return v1.id === v2.id && v1.title === v2.title;
255	          })
256	        );
257	      })
258	    ) {
259	      const current = this.getCurrentFilterTypes();
260	      const active = FilterHelper.setFiltersToURL(this.props.initialFilters, this.state.activeFilters);
261	
262	      this.setState({
263	        currentFilterType: current,
264	        filterTypes: this.props.initialFilters,
265	        activeFilters: active
266	      });
267	
268	      this.loadDynamicFilters();
269	    } else if (
270	      !this.props.cleanState &&
271	      !FilterHelper.filtersMatchURL(this.state.filterTypes, this.state.activeFilters)
272	    ) {
273	      FilterHelper.setFiltersToURL(this.state.filterTypes, this.state.activeFilters);
274	    }
275	
276	    // If the input text changes in typeahead, filter the select options according to the input text value
277	    if (
278	      this.state.currentFilterType.filterType === AllFilterTypes.typeAhead &&
279	      this.state.currentValue !== prevState.currentValue
280	    ) {
281	      const current = Object.assign({}, this.getCurrentFilterTypes());
282	
283	      current.filterValues = current.filterValues.filter(menuItem =>
284	        String(menuItem.title).toLowerCase().includes(this.state.currentValue.toLowerCase())
285	      );
286	
287	      this.setState({
288	        currentFilterType: current,
289	        isFilterValueOpen: true
290	      });
291	    }
292	  }
