313	    const current = activeFilters.filters.filter(filter => filter.category === field.category);
314	    if (field.action === FILTER_ACTION_UPDATE && current.length > 0) {
315	      current.forEach(filter => (filter.value = value));
316	    } else {
317	      activeFilters.filters.push(activeFilter);
318	    }
319	
320	    this.updateActiveFilters(activeFilters);
321	  };
