337	  filterValueSelected = (valueId?: string | number): void => {
338	    const { currentFilterType } = this.state;
339	    const filterValue = currentFilterType.filterValues.find(filter => filter.id === valueId);
340	
341	    if (filterValue && !this.isActive(currentFilterType, filterValue.title)) {
