366	  onTypeaheadInputKeyDown = (keyEvent: React.KeyboardEvent): void => {
367	    const { isFilterValueOpen, focusedItemIndex, currentFilterType } = this.state;
368	
369	    if (keyEvent.key === 'ArrowUp' || keyEvent.key === 'ArrowDown') {
370	      let indexToFocus: number | null = null;
371	
372	      if (this.state.isFilterValueOpen) {
373	        if (keyEvent.key === 'ArrowUp') {
374	          // When no index is set or at the first index, focus to the last, otherwise decrement focus index
375	          if (focusedItemIndex === null || focusedItemIndex === 0) {
376	            indexToFocus = currentFilterType.filterValues.length - 1;
377	          } else {
378	            indexToFocus = focusedItemIndex - 1;
379	          }
380	        } else if (keyEvent.key === 'ArrowDown') {
381	          // When no index is set or at the last index, focus to the first, otherwise increment focus index
382	          if (focusedItemIndex === null || focusedItemIndex === currentFilterType.filterValues.length - 1) {
383	            indexToFocus = 0;
384	          } else {
385	            indexToFocus = focusedItemIndex + 1;
386	          }
387	        }
388	
389	        this.setState({ focusedItemIndex: indexToFocus });
390	      }
391	    } else if (keyEvent.key === 'Enter') {
392	      const focusedItem = focusedItemIndex !== null ? currentFilterType.filterValues[focusedItemIndex] : null;
393	
394	      if (isFilterValueOpen && focusedItem) {
395	        this.filterValueSelected(focusedItem.id);
396	        this.setState({ currentValue: '', focusedItemIndex: null });
397	      }
