409	    const updated = this.state.activeFilters.filters.filter(
410	      x => x.category !== filterCategory || x.value !== filterValue
411	    );
412	
413	    if (updated.length !== this.state.activeFilters.filters.length) {
414	      this.updateActiveFilters({ filters: updated, op: this.state.activeFilters.op });
