556	          isActive={value => this.isActive(currentFilterType, value)}
557	        />
558	      );
559	    } else {
560	      return (
561	        <TextInput
562	          id="filter_input_value"
563	          type={currentFilterType.filterType as TextInputTypes}
564	          value={currentValue}
565	          aria-label="Filter Input Value"
566	          placeholder={t(currentFilterType.placeholder)}
567	          onChange={(_event, value) => this.updateCurrentValue(value)}
568	          onKeyDown={e => this.onValueKeyDown(e)}
569	          style={{ width: 'auto' }}
570	        />
571	      );
572	    }
573	  };
574	
575	  renderChildren = (): React.ReactNode => {
576	    return (
577	      this.props.children && (
578	        <ToolbarGroup style={{ marginRight: '10px' }}>
579	          {Array.isArray(this.props.children) ? (
580	            (this.props.children as Array<any>).map(
581	              (child, index) =>
582	                child && (
583	                  <ToolbarItem
584	                    key={`toolbar_statefulFilters_${index}`}
585	                    className={index === (this.props.children as Array<any>).length - 1 ? paddingStyle : dividerStyle}
586	                  >
587	                    {child}
588	                  </ToolbarItem>
589	                )
590	            )
591	          ) : (
592	            <ToolbarItem>{this.props.children}</ToolbarItem>
593	          )}
594	        </ToolbarGroup>
595	      )
596	    );
597	  };
598	
599	  render(): React.ReactNode {
600	    const showIncludeToggles = serverConfig.kialiFeatureFlags.uiDefaults.list.showIncludeToggles;
601	
602	    const { currentFilterType, activeFilters } = this.state;
603	
604	    const hasActiveFilters =
605	      this.state.activeFilters.filters.some(f => f.category === labelFilter.category) ||
606	      this.state.currentFilterType.filterType === AllFilterTypes.label;
607	
608	    const filterTypeToggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
609	      <MenuToggle
610	        id="filter_select_type-toggle"
611	        className={formSelectStyle}
612	        ref={toggleRef}
613	        onClick={this.onFilterTypeToggle}
614	        isExpanded={this.state.isFilterTypeOpen}
615	        isFullWidth
616	      >
617	        {t(currentFilterType.category)}
618	      </MenuToggle>
619	    );
620	
621	    const filterValueToggle = (toggleRef: React.Ref<MenuToggleElement>): React.ReactNode => (
622	      <MenuToggle
623	        id="filter_select_value-toggle"
624	        ref={toggleRef}
625	        onClick={this.onFilterValueToggle}
626	        isExpanded={this.state.isFilterValueOpen}
627	        isFullWidth
628	      >
629	        {t(activeFilters.op)}
630	      </MenuToggle>
631	    );
632	
633	    return (
634	      <>
635	        <Toolbar
636	          id="filter-selection"
637	          className={this.props.toolbarClass ? classes(toolbarStyle, this.props.toolbarClass) : toolbarStyle}
638	          clearAllFilters={this.clearFilters}
639	        >
640	          {this.props.childrenFirst && this.renderChildren()}
641	          <ToolbarContent>
642	            <ToolbarGroup variant="filter-group">
643	              {this.state.filterTypes.map((ft, i) => (
644	                <ToolbarFilter
645	                  key={`toolbar_filter-${ft.category}`}
646	                  chips={activeFilters.filters
647	                    .filter(af => af.category === ft.category)
648	                    .map(af => ({
649	                      key: af.value,
650	                      node: t(af.value)
651	                    }))}
652	                  deleteChip={this.removeFilter}
653	                  categoryName={{ key: ft.category, name: t(ft.category) }}
654	                >
655	                  {i === 0 && (
656	                    <Select
657	                      id="filter_select_type"
658	                      onSelect={(_event, value) => this.selectFilterType(value as string)}
659	                      onOpenChange={isFilterTypeOpen => this.setState({ isFilterTypeOpen })}
660	                      toggle={filterTypeToggle}
661	                      isOpen={this.state.isFilterTypeOpen}
662	                      aria-label="Filter Select Type"
663	                    >
664	                      <SelectList>
665	                        {this.state.filterTypes.map(option => (
666	                          <SelectOption
667	                            id={option.category}
668	                            key={option.category}
669	                            value={option.category}
670	                            isSelected={option.category === currentFilterType.category}
671	                          >
672	                            {t(option.category)}
673	                          </SelectOption>
674	                        ))}
675	                      </SelectList>
676	                    </Select>
677	                  )}
678	                  {i === 0 && this.renderInput()}
679	                </ToolbarFilter>
680	              ))}
681	            </ToolbarGroup>
682	
683	            <ToolbarGroup>
684	              {showIncludeToggles &&
685	                this.props.initialToggles &&
686	                this.props.initialToggles.map((t, i) => (
687	                  <ToolbarItem key={`toggle-${i}`}>
688	                    <Checkbox
689	                      data-test={`toggle-${t.name}`}
690	                      id={t.name}
691	                      isChecked={Toggles.checked.get(t.name)}
692	                      label={t.label}
693	                      name={t.name}
694	                      onChange={(event, checked: boolean) => this.onCheckboxChange(checked, event)}
695	                    />
696	                  </ToolbarItem>
697	                ))}
698	            </ToolbarGroup>
699	
700	            {!this.props.childrenFirst && this.renderChildren()}
701	
702	            {hasActiveFilters && (
703	              <ToolbarGroup>
704	                <ToolbarItem>
705	                  <div className={paddingStyle}>Label Operation</div>
706	                  <Select
707	                    id="filter_select_value"
708	                    onSelect={(_event, value) => {
709	                      this.updateActiveFilters({
710	                        filters: this.state.activeFilters.filters,
711	                        op: value as LabelOperation
712	                      });
713	                      this.setState({ isFilterValueOpen: false });
714	                    }}
715	                    onOpenChange={isFilterValueOpen => this.setState({ isFilterValueOpen })}
716	                    toggle={filterValueToggle}
717	                    isOpen={this.state.isFilterValueOpen}
718	                    aria-label="Filter Select Value"
719	                  >
720	                    <SelectList>
721	                      <SelectOption
722	                        id={'filter_or'}
723	                        key={'filter_or'}
724	                        value={'or'}
725	                        isSelected={activeFilters.op === 'or'}
726	                      >
727	                        {t('or')}
728	                      </SelectOption>
729	                      <SelectOption
730	                        id={'filter_and'}
731	                        key={'filter_and'}
732	                        value={'and'}
733	                        isSelected={activeFilters.op === 'and'}
734	                      >
735	                        {t('and')}
736	                      </SelectOption>
737	                    </SelectList>
738	                  </Select>
739	                </ToolbarItem>
740	              </ToolbarGroup>
741	            )}
742	          </ToolbarContent>
743	        </Toolbar>
744	        <div className={bottomPadding} />
745	      </>
746	    );
747	  }
748	}
