750	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
751	  language: languageSelector(state)
752	});
753	
754	export const StatefulFilters = connect(mapStateToProps, null, null, { forwardRef: true })(StatefulFiltersComponent);

