 1	import * as React from 'react';
 2	import { mount } from 'enzyme';
 3	import { StatefulFiltersComponent } from '../StatefulFilters';
 4	import { istioSidecarFilter, labelFilter } from '../CommonFilters';
 5	import { ActiveFilter, DEFAULT_LABEL_OPERATION } from '../../../types/Filters';
 6	
 7	const labelValue = 'app:details';
 8	const filterActive: ActiveFilter = { category: labelFilter.category, value: labelValue };
 9	
10	describe('StatefulFilters', () => {
11	  it('add filter', () => {
12	    const stFilter = new StatefulFiltersComponent({
13	      initialFilters: [],
14	      onFilterChange: () => {},
15	      language: 'en'
16	    });
17	
18	    stFilter.filterAdded(labelFilter, labelValue);
19	    expect(stFilter.state.activeFilters).toStrictEqual({ filters: [filterActive], op: DEFAULT_LABEL_OPERATION });
20	  });
21	
22	  it('remove Filter', () => {
23	    const labelVersion = 'version:v1';
24	    const wrapper = mount(
25	      <StatefulFiltersComponent
26	        onFilterChange={jest.fn()}
27	        initialFilters={[labelFilter, istioSidecarFilter]}
28	        language="en"
29	      />
30	    ).instance() as StatefulFiltersComponent;
31	
32	    // Add filters
33	    wrapper.filterAdded(labelFilter, labelValue);
34	    wrapper.filterAdded(labelFilter, labelVersion);
35	    wrapper.filterAdded(istioSidecarFilter, istioSidecarFilter.filterValues[0].id);
36	    wrapper.forceUpdate();
37	    expect(wrapper.state.activeFilters.filters.length).toEqual(3);
38	
39	    // Remove one
40	    wrapper.removeFilter(labelFilter.category, labelValue);
41	    wrapper.forceUpdate();
42	    expect(wrapper.state.activeFilters.filters.length).toEqual(2);
43	    expect(wrapper.state.activeFilters).toStrictEqual({
44	      filters: [
45	        {
46	          category: labelFilter.category,
47	          value: labelVersion
48	        },
49	        {
50	          category: istioSidecarFilter.category,
51	          value: istioSidecarFilter.filterValues[0].id
52	        }
53	      ],
54	      op: DEFAULT_LABEL_OPERATION
55	    });
56	  });
57	});

